const payload = $json;
const collections = [payload.records, payload.items, payload.data, payload.accounts, payload.emails, payload.accounts, payload.deals, payload.meetings, payload.mqls].filter(Boolean);
const rawItems = Array.isArray(collections[0]) ? collections[0] : (Array.isArray(payload.body?.items) ? payload.body.items : []);
const fallback = rawItems.length ? rawItems : [payload.body || payload];
return fallback.filter(Boolean).map((record, index) => ({
  json: {
    workflowId: '13-competitive-displacement-alert',
    workflowName: 'Competitive Displacement Alert',
    sourceKind: 'accounts with engagement drops',
    recordIndex: index + 1,
    record,
    recordSummary: record.name || record.subject || record.accountName || record.opportunityName || record.email || record.id || 'source-record-' + (index + 1)
  }
}));

const item = $json;
const text = item.output || item.response || item.text || '';
return [{ json: { ...item, analysis: text.trim() } }];

const items = $input.all();
const title = "🚨 **Competitive Displacement Alert** — 2 accounts at risk";
const sections = items.map((item, idx) => {
  const name = item.json.recordSummary || 'Record ' + (idx + 1);
  const analysis = (item.json.analysis || '').trim() || '_No analysis returned._';
  return '• *' + name + '*\n' + analysis;
});
const body = [title, '', ...sections].join('\n\n');
return [{ json: { workflowId: '13-competitive-displacement-alert', workflowName: 'Competitive Displacement Alert', messageBody: body, itemCount: items.length } }];

const text = $json.messageBody;
const payload = {
  channel: $json.slackChannelId || $json.channel || 'YOUR_SLACK_CHANNEL_ID',
  text,
  blocks: [{ type: 'section', text: { type: 'mrkdwn', text: text.length > 3000 ? text.slice(0, 2997) + '...' : text } }],
  unfurl_links: false,
  unfurl_media: false
};
return [{ json: { slackPayload: JSON.stringify(payload) } }];
